on":"MEMBER","active_lock_reason":null,"body":"For example

```jl
julia> struct Foo
          x::Int
          y::Bool
       end

julia> Base.datatype_haspadding(Foo)
true

julia> v = [Foo(1, false), Foo(2, false)];

julia> v2 = reinterpret(UInt8, v);

julia> f(v) = @inbounds v[10];

julia> @code_llvm f(v2) # undefined behavior
;  @ REPL[4]:1 within `f'
define i8 @julia_f_196({ {}*, i8, i8 }* nocapture nonnull readonly align 8 dereferenceable(16) %0) {
top:
  ret i8 undef
}
```


Since we are not using any unsafe features here, it would be good to decide on some semantics to avoid undefined behavior. 

